import torch
import torch.nn as nn
import timm

class DomainNetModel(nn.Module):
    def __init__(self, num_classes=345, backbone='vit_base_patch16_clip_224.openai', freeze_backbone=False, drop_rate=0.0):
        super().__init__()
        self.backbone = timm.create_model(backbone, pretrained=True, num_classes=0)
        feat_dim = self.backbone.num_features

        if drop_rate > 0:
            self.classifier = nn.Sequential(
                nn.Dropout(drop_rate),
                nn.Linear(feat_dim, num_classes)
            )
        else:
            self.classifier = nn.Linear(feat_dim, num_classes)

        if freeze_backbone:
            for param in self.backbone.parameters():
                param.requires_grad = False

    def forward(self, x):
        features = self.backbone(x)
        return self.classifier(features)

    def get_features(self, x):
        return self.backbone(x)


class DINOv2Model(nn.Module):
    def __init__(self, num_classes=345, drop_rate=0.0):
        super().__init__()
        from transformers import AutoModel
        self.backbone = AutoModel.from_pretrained('facebook/dinov2-base')
        feat_dim = 768  # DINOv2-base

        if drop_rate > 0:
            self.classifier = nn.Sequential(
                nn.Dropout(drop_rate),
                nn.Linear(feat_dim, num_classes)
            )
        else:
            self.classifier = nn.Linear(feat_dim, num_classes)

    def forward(self, x):
        outputs = self.backbone(x)
        # Use CLS token
        features = outputs.last_hidden_state[:, 0]
        return self.classifier(features)

    def get_features(self, x):
        outputs = self.backbone(x)
        return outputs.last_hidden_state[:, 0]
